package com.company.ops.api.modules.bi.controller;
import com.company.ops.api.common.api.ApiResponse; import com.company.ops.api.modules.bi.dto.BiDtos.CompanyKpiDashboard; import com.company.ops.api.modules.bi.dto.BiDtos.ExecutiveDashboard; import com.company.ops.api.modules.bi.service.BiService; import java.time.LocalDate; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/bi") public class BiController{private final BiService service;public BiController(BiService service){this.service=service;}@GetMapping("/dashboard")@PreAuthorize("hasAnyAuthority('bi:view','dashboard:view')")public ApiResponse<ExecutiveDashboard> dashboard(){return ApiResponse.ok(service.dashboard());}@GetMapping("/company-dashboard")@PreAuthorize("hasAnyAuthority('bi:view','dashboard:view')")public ApiResponse<CompanyKpiDashboard> companyDashboard(@RequestParam(required=false) LocalDate startDate,@RequestParam(required=false) LocalDate endDate){return ApiResponse.ok(service.companyDashboard(startDate,endDate));}}
